```python
import os
import json
import asyncio
from datetime import datetime, timedelta
from fastapi import FastAPI, Request
from fastapi.responses import HTMLResponse, JSONResponse
from fastapi.staticfiles import StaticFiles
from fastapi.templating import Jinja2Templates
import uvicorn
import anthropic
from typing import Dict, List

app = FastAPI()
templates = Jinja2Templates(directory="templates")

# Initialize Claude client
try:
    claude_client = anthropic.Anthropic(api_key=os.environ.get("ANTHROPIC_API_KEY"))
except:
    claude_client = None

class DevelopmentDashboard:
    def __init__(self):
        self.load_mock_data()
        self.ai_agent_active = True

    def load_mock_data(self):
        """Load all mock data for the demo"""
        with open('data/backlog_items.json', 'r') as f:
            self.backlog = json.load(f)
        with open('data/incidents.json', 'r') as f:
            self.incidents = json.load(f)
        with open('data/ai_progress.json', 'r') as f:
            self.ai_progress = json.load(f)
        with open('data/system_metrics.json', 'r') as f:
            self.metrics = json.load(f)

    def get_active_incidents(self):
        """Get current firefighting incidents"""
        return [inc for inc in self.incidents if inc["status"] == "active"]

    def get_ai_current_task(self):
        """Get what the AI agent is currently working on"""
        for task in self.ai_progress:
            if task["status"] == "in_progress":
                return task
        return None

    def get_recent_completions(self):
        """Get recently completed AI tasks"""
        return [task for task in self.ai_progress if task["status"] == "completed"][-3:]

dashboard = DevelopmentDashboard()

async def generate_code_with_ai(task_description: str) -> str:
    """Generate code for a task using Claude API"""
    if not claude_client:
        # Fallback mock code generation
        mock_code = f"""
// AI-Generated Implementation for: {task_description}

class SecurityModule {{
    constructor(config) {{
        this.config = config;
        this.auditLogger = new AuditLogger();
    }}

    async validateRequest(request) {{
        // SOC 2 compliant request validation
        const result = await this.performSecurityChecks(request);
        this.auditLogger.log('security_validation', result);
        return result;
    }}

    performSecurityChecks(request) {{
        // Implementation would validate against OTM Cyber's security policies
        return {{ valid: true, riskScore: 0.2 }};
    }}
}}

export default SecurityModule;
        """
        return mock_code.strip()

    try:
        message = claude_client.messages.create(
            model="claude-3-sonnet-20240229",
            max_tokens=1000,
            system=f"""You are an AI development agent for OTM Cyber, a cybersecurity company. 
            Generate clean, production-ready code for: {task_description}

            Focus on:
            - Security-first design patterns
            - SOC 2 compliance considerations  
            - Clean, maintainable code
            - Proper error handling

            Return only the code, no explanations.""",
            messages=[{"role": "user", "content": f"Implement: {task_description}"}]
        )
        return message.content[0].text
    except:
        # Fallback if API fails
        return f"// AI-generated code for: {task_description}\n// (Live generation temporarily unavailable - using fallback)"

@app.get("/", response_class=HTMLResponse)
async def dashboard_home(request: Request):
    """Main dashboard view"""
    return templates.TemplateResponse("dashboard.html", {
        "request": request,
        "active_incidents": dashboard.get_active_incidents(),
        "ai_current_task": dashboard.get_ai_current_task(),
        "recent_completions": dashboard.get_recent_completions(),
        "metrics": dashboard.metrics,
        "company_name": "OTM Cyber"
    })

@app.get("/api/incidents")
async def get_incidents():
    """API endpoint for incident data"""
    return JSONResponse({
        "active": dashboard.get_active_incidents(),
        "total_count": len(dashboard.incidents),
        "human_dev_utilization": "95%"
    })

@app.get("/api/ai-progress")
async def get_ai_progress():
    """API endpoint for AI agent progress"""
    current_task = dashboard.get_ai_current_task()

    if current_task and current_task.get("generate_code"):
        # Generate live code for current task
        code = await generate_code_with_ai(current_task["title"])
        current_task["generated_code"] = code

    return JSONResponse({
        "current_task": current_task,
        "recent_completions": dashboard.get_recent_completions(),
        "backlog_remaining": len([t for t in dashboard.backlog if t["status"] == "todo"]),
        "ai_velocity": "3.2 story points/day"
    })

@app.get("/api/metrics")
async def get_system_metrics():
    """API endpoint for system health metrics"""
    return JSONResponse(dashboard.metrics)

@app.get("/api/generate-code/{task_id}")
async def generate_code_live(task_id: str):
    """Generate code for a specific task"""
    task = next((t for t in dashboard.backlog if t["id"] == task_id), None)
    if not task:
        return JSONResponse({"error": "Task not found"})

    code = await generate_code_with_ai(task["title"])
    return JSONResponse({
        "task_id": task_id,
        "generated_code": code,
        "compliance_check": "PASSED",
        "security_scan": "CLEAN",
        "timestamp": datetime.now().isoformat()
    })

@app.get("/api/fallback")
async def load_fallback_data():
    """Load fallback data if live sources fail"""
    dashboard.load_mock_data()
    return JSONResponse({"status": "Fallback data loaded successfully"})

if __name__ == "__main__":
    port = int(os.environ.get("PORT", 8000))
    uvicorn.run(app, host="0.0.0.0", port=port)
```

